class MalformedInputError(Exception):
    pass

class InputProcessor:
    def __init__(self):
        self.values = []

    def process_user_input(self, input_str):
        try:
            parts = input_str.strip().split()
            if len(parts) != 3 or parts[0] not in ['add', 'subtract']:
                raise MalformedInputError("Invalid input format")

            op, x, y = parts
            x = float(x)
            y = float(y)

            if op == 'add':
                self.values.append(x + y)
            elif op == 'subtract':
                self.values.append(x - y)
            else:
                raise MalformedInputError("Unsupported operation")
        except MalformedInputError as e:
            print(e)

    def get_values(self):
        return self.values

processor = InputProcessor()
processor.process_user_input('123')
assert 'MalformedInputError' in str(processor.get_values()), "MalformedInputError was not raised for '123'"

